sys_script.script:
(function executeRule(current, previous /*null when async*/) {

    try {
        var incGR = new GlideRecord('incident');
        incGR.initialize();

        var citizenName  = current.getValue('u_citizen_name') || "Anonymous Citizen";
        var citizenEmail = current.getValue('u_citizen_email') || "Not Provided";
        var locationText = current.getValue('u_physical_location') || "Not Provided";
        var shortSummary = current.getValue('u_summary') || "Public Community Hazard Report";

        // --- SECURE FORM THREAD INTERCEPTION ---
        // Pulls the text area input straight out of the active widget memory context thread
        var detailText = "";
        if (typeof input !== 'undefined' && input && input.description) {
            detailText = "Contact Phone: " + (input.reporter_phone || "Not Provided") + "\n\n" +
                         "Detailed Situation Breakdown:\n" + input.description;
        } else {
            // Fallback safety route
            detailText = current.getValue('u_details') || current.getValue('u_description') || "No text payload captured from form description field.";
        }

        incGR.short_description = "Public Hazard: " + shortSummary;

        // Map everything beautifully inside the standard Incident Description field box
        var formattedNotes = "Reporter Name: " + citizenName + "\n" +
                             "Contact Email: " + citizenEmail + "\n" +
                             "Reported Location: " + locationText + "\n\n" +
                             "=========================================\n" +
                             "DETAILED SITUATION DESCRIPTION:\n" + 
                             "=========================================\n" + 
                             detailText;

        incGR.description = formattedNotes;
        incGR.contact_type = "web";

        // Link the incident record directly back to your custom logging request row
        incGR.parent = current.getUniqueValue(); 

        incGR.insert();

    } catch (err) {
        gs.error("Failed to spawn background incident from public portal submission: " + err.message);
    }

})(current, previous);
